SELECT * FROM(SELECT DISTINCT PGM_YR,ADM_ST_FSA_CD,ADM_CNTY_FSA_CD,OFR_TR_NBR,OFR_SCNR_NM,SGNP_TYPE_DESC,SGNP_STYPE_DESC,SGNP_NBR,SGNP_STYPE_AGR_NM,OFR_FARM_NBR,FARM_NBR,TR_NBR,CPLD_ACRG,MPL_ACRG,NIPF_ACRG,CNSV_CTR_SEQ_NBR,CNSV_CTR_SFX_CD,OFR_FARM_TR_ID,OFR_SCNR_ID,DATA_STAT_CD,CRE_DT,LAST_CHG_DT,LAST_CHG_USER_NM,-- op,ROW_NUMBER() over ( partition by OFR_FARM_TR_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR OFR_TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.FARM_NBR OFR_FARM_NBR,offer_farm_tract.FARM_NBR FARM_NBR,offer_farm_tract.TR_NBR TR_NBR,offer_farm_tract.CPLD_ACRG CPLD_ACRG,offer_farm_tract.MPL_ACRG MPL_ACRG,offer_farm_tract.NIPF_ACRG NIPF_ACRG,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,offer_farm_tract.OFR_FARM_TR_ID OFR_FARM_TR_ID,offer_farm_tract.OFR_SCNR_ID OFR_SCNR_ID,offer_farm_tract.DATA_STAT_CD DATA_STAT_CD,offer_farm_tract.CRE_DT CRE_DT,offer_farm_tract.LAST_CHG_DT LAST_CHG_DT,offer_farm_tract.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,1 AS TBL_PRIORITYFROM "fsa-prod-cnsv".OFFER_FARM_TRACT   LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (OFFER_FARM_TRACT.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN EWT14SGNP ON(EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)  -- WHERE __CDC_OPERATION <> 'D'UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR OFR_TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.FARM_NBR OFR_FARM_NBR,offer_farm_tract.FARM_NBR FARM_NBR,offer_farm_tract.TR_NBR TR_NBR,offer_farm_tract.CPLD_ACRG CPLD_ACRG,offer_farm_tract.MPL_ACRG MPL_ACRG,offer_farm_tract.NIPF_ACRG NIPF_ACRG,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,offer_farm_tract.OFR_FARM_TR_ID OFR_FARM_TR_ID,offer_farm_tract.OFR_SCNR_ID OFR_SCNR_ID,offer_farm_tract.DATA_STAT_CD DATA_STAT_CD,offer_farm_tract.CRE_DT CRE_DT,offer_farm_tract.LAST_CHG_DT LAST_CHG_DT,offer_farm_tract.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,2 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT40OFRSC JOIN "fsa-prod-cnsv".OFFER_FARM_TRACT    ON (OFFER_FARM_TRACT.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON(EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)  -- WHERE __CDC_OPERATION <> 'D'UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR OFR_TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.FARM_NBR OFR_FARM_NBR,offer_farm_tract.FARM_NBR FARM_NBR,offer_farm_tract.TR_NBR TR_NBR,offer_farm_tract.CPLD_ACRG CPLD_ACRG,offer_farm_tract.MPL_ACRG MPL_ACRG,offer_farm_tract.NIPF_ACRG NIPF_ACRG,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,offer_farm_tract.OFR_FARM_TR_ID OFR_FARM_TR_ID,offer_farm_tract.OFR_SCNR_ID OFR_SCNR_ID,offer_farm_tract.DATA_STAT_CD DATA_STAT_CD,offer_farm_tract.CRE_DT CRE_DT,offer_farm_tract.LAST_CHG_DT LAST_CHG_DT,offer_farm_tract.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,3 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT14SGNP LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON(EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)JOIN "fsa-prod-cnsv".OFFER_FARM_TRACT ON (OFFER_FARM_TRACT.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) --WHERE __CDC_OPERATION <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND (
 (COALESCE(CAST(CRE_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
    AND
    (COALESCE(CAST(LAST_CHG_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
)

UNIONSELECT DISTINCTNULL PGM_YR,NULL ADM_ST_FSA_CD,NULL ADM_CNTY_FSA_CD,NULL OFR_TR_NBR,NULL OFR_SCNR_NM,NULL SGNP_TYPE_DESC,NULL SGNP_STYPE_DESC,NULL SGNP_NBR,NULL SGNP_STYPE_AGR_NM,NULL OFR_FARM_NBR,offer_farm_tract.FARM_NBR FARM_NBR,offer_farm_tract.TR_NBR TR_NBR,offer_farm_tract.CPLD_ACRG CPLD_ACRG,offer_farm_tract.MPL_ACRG MPL_ACRG,offer_farm_tract.NIPF_ACRG NIPF_ACRG,NULL CNSV_CTR_SEQ_NBR,NULL CNSV_CTR_SFX_CD,offer_farm_tract.OFR_FARM_TR_ID OFR_FARM_TR_ID,offer_farm_tract.OFR_SCNR_ID OFR_SCNR_ID,offer_farm_tract.DATA_STAT_CD DATA_STAT_CD,offer_farm_tract.CRE_DT CRE_DT,offer_farm_tract.LAST_CHG_DT LAST_CHG_DT,offer_farm_tract.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- 'D' CDC_OPER_CD,1 AS row_num_partFROM "fsa-prod-cnsv".offer_farm_tract-- WHERE __CDC_OPERATION = 'D'